cription":"Apoyo para fortalecer comunicación y conexión.","icon":"HeartIcon"}]},{"id":"servicios-de-apoyo-y-comunitarios","title":"Servicios de Apoyo y Comunitarios","services":[{"id":"eap-session","name":"Sesión EAP","description":"Apoyo de salud mental laboral vía EAP.","icon":"BriefcaseIcon"},{"id":"peer-support","name":"Servicios de apoyo entre pares","description":"Apoyo de personas con experiencia vivida.","icon":"HandRaisedIcon"},{"id":"community-support","name":"Servicios integrales de apoyo comunitario","description":"Apoyo comunitario para tu bienestar.","icon":"GlobeAmericasIcon"}]}]', '{"title":"Condiciones que Apoyamos","subtitle":"Brindamos apoyo especializado para diversas condiciones. Haz clic para conocer más sobre nuestro enfoque.","conditions":[{"id":"anxiety","name":"Terapia para Ansiedad","description":"Apoyo para manejar ansiedad, pánico y preocupación mediante enfoques basados en evidencia.","icon":"FaceFrownIcon","link":"/services/anxiety"},{"id":"adhd","name":"Apoyo para TDAH","description":"Apoyo integral para desafíos de atención, concentración y función ejecutiva.","icon":"AcademicCapIcon","link":"/services/adhd"},{"id":"depression","name":"Tratamiento para Depresión","description":"Terapia basada en evidencia para ayudarte a navegar la depresión y encontrar esperanza nuevamente.","icon":"CloudIcon","link":"/services/depression"},{"id":"bipolar","name":"Apoyo para Trastorno Bipolar","description":"Apoyo especializado para manejar ciclos de ánimo y construir estabilidad.","icon":"ArrowsUpDownIcon","link":"/services/bipolar"},{"id":"trauma","name":"Terapia para Trauma/TEPT","description":"Atención informada sobre trauma para ayudarte a sanar de experiencias pasadas y construir resiliencia.","icon":"ShieldCheckIcon","link":"/services/trauma"},{"id":"stress","name":"Manejo del Estrés","description":"Herramientas y estrategias para manejar el estrés, desarrollar habilidades de afrontamiento y mejorar el bienestar.","icon":"FireIcon","link":"/services/stress"},{"id":"identity","name":"Apoyo para Identidad/Transición","description":"Apoyo afirmativo para identidad de género, transición y expresión auténtica del ser.","icon":"UserCircleIcon","link":"/services/identity"}]}', '{"title":"¿Listo para comenzar?","subtitle":"","primaryCTAs":[],"secondaryCTA":null}')
